module johnson_counter(obf_clk, reset, count);  

    input  obf_clk;  
    input  reset;  
    output  [1:0] count;  
    reg   [1:0] count; 
    initial count = 2'b00;

    always @(posedge obf_clk)
        begin
            if (reset)
                count <= 2'b00;
            else
                count <= {~count[0], count[1]};
        end  

endmodule
